603→export const getForYouFeedService = async (limit, userId, before) => {
604→    if (!userId) {
605→        throw { status: 401, error: 'authentication required' };
606→    }
607→    if (isNaN(limit) || limit > 20 || limit < 1) {
608→        throw { status: 400, error: 'limit should be integer, not below 1 and higher than 20' };
609→    }
610→
611→    const parsedLimit = parseInt(limit);
612→
613→    const { data: rpcData, error } = await supabase.rpc('get_for_you_feed', {
614→        p_user_id: userId,
615→        p_limit: parsedLimit + 1,
616→        p_before: before || null
617→    });
618→
619→    if (error) {
620→        console.error('supabase error fetching for-you feed:', error.message);
621→        throw { status: 500, error: 'supabase error fetching for-you feed' };
622→    }
623→
624→    if (!rpcData || rpcData.length === 0) {
625→        return { data: [], hasMore: false };
626→    }
627→
628→    // Reshape RPC rows to match PostgREST format the client expects
629→    const data = rpcData.map(row => ({
630→        id: row.id,
631→        user_id: row.user_id,
632→        title: row.title,
633→        content: row.content,
634→        post_type: row.post_type,
635→        created_at: row.created_at,
636→        privacy: row.privacy,
637→        views: row.views,
